import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { baiDangAPI, thongKeAPI } from '../services/api';
import RoomCard from '../components/room/RoomCard';
import './TrangChu.css';

const dinhDangSo = value => new Intl.NumberFormat('vi-VN').format(value || 0);

export default function TrangChu() {
  const [baiDangMoi, setBaiDangMoi] = useState([]);
  const [thongKe, setThongKe] = useState({
    tongNguoiDung: 0,
    tongPhongSanSang: 0,
    tongBaiDangDangHienThi: 0,
    tongTaiKhoanXacThuc: 0,
  });
  const [tuKhoa, setTuKhoa] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    baiDangAPI.layDanhSach({ page: 0, size: 6 })
      .then(r => setBaiDangMoi(r.data.data?.content || []))
      .catch(() => {});

    thongKeAPI.layTrangChu()
      .then(r => {
        if (r.data?.data) {
          setThongKe(r.data.data);
        }
      })
      .catch(() => {});
  }, []);

  const handleSearch = e => {
    e.preventDefault();
    navigate(`/bai-dang?tuKhoa=${encodeURIComponent(tuKhoa)}`);
  };

  const thongKeTrangChu = [
    { value: dinhDangSo(thongKe.tongNguoiDung), label: 'Nguoi dung' },
    { value: dinhDangSo(thongKe.tongPhongSanSang), label: 'Phong tro san sang' },
    { value: dinhDangSo(thongKe.tongBaiDangDangHienThi), label: 'Bai dang dang hien thi' },
    { value: dinhDangSo(thongKe.tongTaiKhoanXacThuc), label: 'Tai khoan da xac thuc' },
  ];

  return (
    <div>
      <section className="hero">
        <div className="container hero-content">
          <h1 className="hero-title">Tim ban o ghep<br /><span>de dang va an toan</span></h1>
          <p className="hero-subtitle">
            Ket noi hang nghin nguoi tim phong va chia se tien thue.<br />
            Xac thuc danh tinh, minh bach, dang tin cay.
          </p>
          <form className="hero-search" onSubmit={handleSearch}>
            <input
              className="form-control"
              placeholder="Nhap khu vuc, dia chi..."
              value={tuKhoa}
              onChange={e => setTuKhoa(e.target.value)}
            />
            <button type="submit" className="btn btn-primary btn-lg">Tim phong</button>
          </form>
          <div className="hero-actions">
            <Link to="/tao-bai-dang" className="btn btn-outline btn-lg">Dang tin tim ban ghep</Link>
            <Link to="/tao-phong" className="btn btn-secondary btn-lg">Dang phong</Link>
          </div>
        </div>
      </section>

      <section className="stats-section">
        <div className="container">
          <div className="grid-4">
            {thongKeTrangChu.map(s => (
              <div key={s.label} className="stat-card">
                <div className="stat-value">{s.value}</div>
                <div className="stat-label">{s.label}</div>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section className="features-section">
        <div className="container">
          <h2 className="section-title text-center">Tai sao chon RoomMate?</h2>
          <p className="section-subtitle text-center">Nen tang dang tin cay voi nhieu tinh nang vuot troi</p>
          <div className="grid-3">
            {[
              { icon: 'OCR', title: 'Xac thuc CCCD bang OCR', desc: 'Xac minh danh tinh tu dong, tang do tin cay giua nguoi thue' },
              { icon: 'VND', title: 'Chia tien tu dong', desc: 'He thong tu chia deu tien phong cho cac thanh vien' },
              { icon: 'PDF', title: 'Dang ky tam tru', desc: 'Tu dong tao phieu tam tru, xuat file gui cong an khu vuc' },
              { icon: 'Chat', title: 'Chat truc tiep', desc: 'Nhan tin, trao doi ngay trong app truoc khi quyet dinh' },
              { icon: 'Map', title: 'Ban do tich hop', desc: 'Xem vi tri phong, so sanh khoang cach den truong hoac co quan' },
              { icon: 'Star', title: 'Danh gia minh bach', desc: 'Danh gia ban cung phong va chu nha sau khi o' },
            ].map(f => (
              <div key={f.title} className="feature-card">
                <div className="feature-icon">{f.icon}</div>
                <h3>{f.title}</h3>
                <p>{f.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section className="latest-section">
        <div className="container">
          <div className="section-header">
            <div>
              <h2 className="section-title">Tin dang moi nhat</h2>
              <p className="section-subtitle">Cac phong tro va tim ban ghep moi nhat</p>
            </div>
            <Link to="/bai-dang" className="btn btn-outline">Xem tat ca -></Link>
          </div>
          <div className="grid-3">
            {baiDangMoi.map(bd => <RoomCard key={bd.maBaiDang} baiDang={bd} />)}
          </div>
        </div>
      </section>

      <section className="cta-section">
        <div className="container cta-content">
          <h2>San sang tim ban o ghep?</h2>
          <p>Dang ky mien phi ngay hom nay va ket noi voi hang nghin nguoi.</p>
          <Link to="/dang-ky" className="btn btn-primary btn-lg">Bat dau mien phi</Link>
        </div>
      </section>
    </div>
  );
}
